/**
  * 表格弹窗
  * @param options 配置
  * 说明：具体配置可参考
  * modal 为弹窗的配置
  * table 为表格的配置
  * 说明：具体配置可参考 https://ant.design/index-cn 中的Modal、Table组件API
  */
MKXFORM.tableModal({
  modal: {
    onOk() {
      console.log(点击确认)
    },
    onCancel() {
      console.log(点击取消)
    },
  },
  table: {
    columns: [
      {
          title: 'Name',
          key: 'name',
          dataIndex: 'name'
      },
      {
          title: 'Age',
          key: 'age',
          dataIndex: 'age'
      },
      {
          title: 'Address',
          key: 'address',
          dataIndex: 'address'
      },
      {
          title: 'Tags',
          key: 'tags',
          dataIndex: 'tags'
      }
    ],
    dataSource: [
      {
          key: '1',
          name: 'John Brown',
          age: 32,
          address: 'New York No. 1 Lake Park',
          tags: 'cool',
      }
    ]
}
})

